// Weather data with error handling
let weatherInfo;
try {
  const weather = $node["HTTP Request"].json;
  const city = weather.name;
  const temp = weather.main.temp;
  const description = weather.weather[0].description;
  weatherInfo = `🌤 Weather in ${city}:\n${temp}°C — ${description}`;
} catch (error) {
  weatherInfo = `🌤 Weather: unavailable right now`;
}

// News data with error handling
let newsInfo;
try {
  const news = $node["HTTP Request1"].json;
  const headlines = news.articles.slice(0, 3).map((article, index) => {
    return `${index + 1}. ${article.title}`;
  }).join("\n");
  newsInfo = `📰 Top Tech News:\n${headlines}`;
} catch (error) {
  newsInfo = `📰 News: unavailable right now`;
}

// GitHub data with error handling
let githubInfo;
try {
  const github = $node["HTTP Request2"].json;
  githubInfo = `💻 GitHub: ${github.login}\nPublic Repos: ${github.public_repos}`;
} catch (error) {
  githubInfo = `💻 GitHub: unavailable right now`;
}

// Crypto data with error handling
let cryptoInfo;
try {
  const crypto = $node["HTTP Request4"].json;
  const btcPrice = crypto.bitcoin.usd.toLocaleString();
  const btcChange = crypto.bitcoin.usd_24h_change.toFixed(2);
  const ethPrice = crypto.ethereum.usd.toLocaleString();
  const ethChange = crypto.ethereum.usd_24h_change.toFixed(2);
  const solPrice = crypto.solana.usd.toLocaleString();
  const solChange = crypto.solana.usd_24h_change.toFixed(2);
  cryptoInfo = `💰 Crypto Watch:\nBTC: $${btcPrice} (${btcChange}%)\nETH: $${ethPrice} (${ethChange}%)\nSOL: $${solPrice} (${solChange}%)`;
} catch (error) {
  cryptoInfo = `💰 Crypto: unavailable right now`;
}

// Calendar (today's events)
let calendarInfo;
try {
  const events = $('Get many events').all();

  // Filter out phantom empty items (from "Always Output Data")
  const validEvents = events.filter(item => 
    item.json && item.json.start && item.json.start.dateTime
  );

  if (validEvents.length === 0) {
    calendarInfo = "📅 Today's Schedule: Free day! No meetings, all focus 🎯";
  } else {
    const formatted = validEvents.map(item => {
      const event = item.json;
      const startTime = new Date(event.start.dateTime).toLocaleTimeString('en-US', {
        hour: 'numeric',
        minute: '2-digit',
        hour12: true,
        timeZone: 'Asia/Kolkata'
      });
      return `- ${startTime}: ${event.summary || 'Untitled event'}`;
    }).join('\n');

    calendarInfo = `📅 Today's Schedule:\n${formatted}`;
  }
} catch (error) {
  calendarInfo = "📅 Today's Schedule: Could not fetch calendar";
}


// Build final message
const message = `
🌅 Good Morning Radhika!

${weatherInfo}

${newsInfo}

${githubInfo}

${cryptoInfo}

${calendarInfo}

Have a productive day! 🚀
`;

return [{ json: { message } }];

